import { useState } from "react";

const toppings = [
  { emoji: "🍄", name: "Mushroom", price: 40 },
  { emoji: "🫒", name: "Olives", price: 35 },
  { emoji: "🌽", name: "Corn", price: 30 },
  { emoji: "🧅", name: "Onion", price: 20 },
  { emoji: "🌶️", name: "Chilli", price: 25 },
  { emoji: "🍍", name: "Pineapple", price: 50 },
  { emoji: "🥓", name: "Bacon", price: 60 },
  { emoji: "🧀", name: "Extra Cheese", price: 45 },
];

export default function PizzaBuilder() {
  const [pizza, setPizza] = useState([]);

  function addTopping(topping) {
    setPizza([
      ...pizza,
      {
        ...topping,
        x: 15 + Math.random() * 70,
        y: 15 + Math.random() * 70,
      },
    ]);
  }

  function clearPizza() {
    setPizza([]);
  }

  const total = 299 + pizza.reduce((sum, t) => sum + t.price, 0);

  return (
    <div className="container">
      <h1>🍕 Pizza Builder</h1>

      <h2>Total: ₹{total}</h2>

      <div
        style={{
          position: "relative",
          width: 320,
          height: 320,
          margin: "1rem",
        }}
      >
        <img
          src="https://www.shutterstock.com/image-illustration/pizza-no-topping-260nw-2685328587.jpg"
          alt="Pizza"
          style={{
            width: "100%",
            height: "100%",
            objectFit: "cover",
            borderRadius: "50%",
          }}
        />

        {pizza.map((topping, i) => (
          <span
            key={i}
            style={{
              position: "absolute",
              left: `${topping.x}%`,
              top: `${topping.y}%`,
              fontSize: "1.8rem",
              transform: "translate(-50%, -50%)",
            }}
          >
            {topping.emoji}
          </span>
        ))}
      </div>

      <div>
        {toppings.map((topping) => (
          <button
            key={topping.name}
            onClick={() => addTopping(topping)}
          >
            {topping.emoji} ₹{topping.price}
          </button>
        ))}
      </div>

      <button onClick={clearPizza}>Clear Pizza</button>
    </div>
  );
}
